CREATE TABLE [hubspot].[landing_pages] (
    [id] NVARCHAR(450) NOT NULL,
    [name] NVARCHAR(MAX) NULL,
    [slug] NVARCHAR(MAX) NULL,
    [htmlTitle] NVARCHAR(MAX) NULL,
    [state] NVARCHAR(MAX) NULL,
    [currentState] NVARCHAR(MAX) NULL,
    [subcategory] NVARCHAR(MAX) NULL,
    [contentGroupId] NVARCHAR(MAX) NULL,
    [domain] NVARCHAR(MAX) NULL,
    [url] NVARCHAR(MAX) NULL,
    [absoluteUrl] NVARCHAR(MAX) NULL,
    [templatePath] NVARCHAR(MAX) NULL,
    [templateType] NVARCHAR(MAX) NULL,
    [metaDescription] NVARCHAR(MAX) NULL,
    [featuredImage] NVARCHAR(MAX) NULL,
    [featuredImageAlt] NVARCHAR(MAX) NULL,
    [campaign] NVARCHAR(MAX) NULL,
    [language] NVARCHAR(MAX) NULL,
    [translatedFromId] NVARCHAR(MAX) NULL,
    [folderId] NVARCHAR(MAX) NULL,
    [authorName] NVARCHAR(MAX) NULL,
    [enableDomainStylesheets] NVARCHAR(MAX) NULL,
    [enableLayoutStylesheets] NVARCHAR(MAX) NULL,
    [includeDefaultCustomCss] NVARCHAR(MAX) NULL,
    [pageRedirected] NVARCHAR(MAX) NULL,
    [redirectUrl] NVARCHAR(MAX) NULL,
    [noindex] NVARCHAR(MAX) NULL,
    [canonicalUrl] NVARCHAR(MAX) NULL,
    [publishDate] NVARCHAR(MAX) NULL,
    [created] NVARCHAR(MAX) NULL,
    [updated] NVARCHAR(MAX) NULL,
    [archivedAt] NVARCHAR(MAX) NULL,
    [archivedInDashboard] NVARCHAR(MAX) NULL,
    [__mj_integration_SyncStatus] NVARCHAR(50) NOT NULL DEFAULT 'Active',
    [__mj_integration_LastSyncedAt] DATETIMEOFFSET NULL,
    CONSTRAINT [UQ_hubspot_landing_pages_PK] UNIQUE ([id])
);

