    [hs_lastmodifieddate] DATETIMEOFFSET NULL,
    [hs_meeting_body] NVARCHAR(MAX) NULL,
    [hs_meeting_end_time] DATETIMEOFFSET NULL,
    [hs_meeting_location] NVARCHAR(255) NULL,
    [hs_meeting_location_type] NVARCHAR(MAX) NULL,
    [hs_meeting_outcome] NVARCHAR(MAX) NULL,
    [hs_meeting_source] NVARCHAR(MAX) NULL,
    [hs_meeting_start_time] DATETIMEOFFSET NULL,
    [hs_meeting_title] NVARCHAR(255) NULL,
    [hs_merged_object_ids] NVARCHAR(MAX) NULL,
    [hs_object_id] NVARCHAR(450) NOT NULL,
    [hs_object_source_detail_1] NVARCHAR(255) NULL,
    [hs_object_source_detail_2] NVARCHAR(255) NULL,
    [hs_object_source_detail_3] NVARCHAR(255) NULL,
