    [hs_shared_team_ids] NVARCHAR(MAX) NULL,
    [hs_shared_user_ids] NVARCHAR(MAX) NULL,
    [hs_time_to_book_meeting_from_first_contact] NVARCHAR(MAX) NULL,
    [hs_timestamp] DATETIMEOFFSET NULL,
    [hs_updated_by_user_id] NVARCHAR(MAX) NULL,
    [hs_video_conference_platform] NVARCHAR(MAX) NULL,
    [hs_video_conference_url] NVARCHAR(255) NULL,
    [hubspot_owner_id] NVARCHAR(MAX) NULL,
    [hubspot_team_id] NVARCHAR(MAX) NULL,
    [__mj_integration_SyncStatus] NVARCHAR(50) NOT NULL DEFAULT 'Active',
