CREATE TABLE [hubspot].[tasks] (
    [hs_attachment_ids] NVARCHAR(MAX) NULL,
    [hs_body_preview] NVARCHAR(255) NULL,
    [hs_created_by] NVARCHAR(MAX) NULL,
    [hs_created_by_user_id] NVARCHAR(MAX) NULL,
    [hs_createdate] DATETIMEOFFSET NULL,
    [hs_lastmodifieddate] DATETIMEOFFSET NULL,
    [hs_merged_object_ids] NVARCHAR(MAX) NULL,
    [hs_object_id] NVARCHAR(450) NOT NULL,
    [hs_object_source_detail_1] NVARCHAR(255) NULL,
    [hs_object_source_detail_2] NVARCHAR(255) NULL,
    [hs_object_source_detail_3] NVARCHAR(255) NULL,
    [hs_object_source_label] NVARCHAR(MAX) NULL,
    [hs_pipeline] NVARCHAR(MAX) NULL,
    [hs_pipeline_stage] NVARCHAR(MAX) NULL,
    [hs_queue_membership_ids] NVARCHAR(MAX) NULL,
    [hs_repeat_status] NVARCHAR(MAX) NULL,
    [hs_shared_team_ids] NVARCHAR(MAX) NULL,
    [hs_shared_user_ids] NVARCHAR(MAX) NULL,
    [hs_start_date] DATETIMEOFFSET NULL,
    [hs_target_duration] NVARCHAR(MAX) NULL,
    [hs_task_assigned_by_user_id] NVARCHAR(MAX) NULL,
    [hs_task_assigned_contacts] NVARCHAR(MAX) NULL,
    [hs_task_blocked_task_ids] NVARCHAR(MAX) NULL,
    [hs_task_blocking_task_ids] NVARCHAR(MAX) NULL,
    [hs_task_body] NVARCHAR(MAX) NULL,
    [hs_task_company_domain] NVARCHAR(255) NULL,
    [hs_task_company_industry] NVARCHAR(MAX) NULL,
    [hs_task_company_is_target_account] BIT NULL,
    [hs_task_completion_date] DATETIMEOFFSET NULL,
    [hs_task_contact_email] NVARCHAR(255) NULL,
    [hs_task_contact_job_title] NVARCHAR(255) NULL,
    [hs_task_contact_phone] NVARCHAR(255) NULL,
    [hs_task_contact_timezone] NVARCHAR(255) NULL,
    [hs_task_is_open] BIT NULL,
    [hs_task_is_overdue] BIT NULL,
    [hs_task_is_past_due_date] BIT NULL,
    [hs_task_last_contact_outreach] DATETIMEOFFSET NULL,
    [hs_task_last_sales_activity_timestamp] DATETIMEOFFSET NULL,
    [hs_task_priority] NVARCHAR(MAX) NULL,
    [hs_task_reminders] NVARCHAR(MAX) NULL,
    [hs_task_repeat_interval] NVARCHAR(255) NULL,
    [hs_task_sequence_enrollment_active] BIT NULL,
    [hs_task_sequence_id] NVARCHAR(MAX) NULL,
    [hs_task_sequence_step_number] NVARCHAR(MAX) NULL,
    [hs_task_status] NVARCHAR(MAX) NULL,
    [hs_task_sub_task_ids] NVARCHAR(MAX) NULL,
    [hs_task_subject] NVARCHAR(255) NULL,
    [hs_task_type] NVARCHAR(MAX) NULL,
    [hs_timestamp] DATETIMEOFFSET NULL,
    [hs_updated_by_user_id] NVARCHAR(MAX) NULL,
    [hubspot_owner_assigneddate] DATETIMEOFFSET NULL,
    [hubspot_owner_id] NVARCHAR(MAX) NULL,
    [hubspot_team_id] NVARCHAR(MAX) NULL,
    [__mj_integration_SyncStatus] NVARCHAR(50) NOT NULL DEFAULT 'Active',
    [__mj_integration_LastSyncedAt] DATETIMEOFFSET NULL,
    CONSTRAINT [UQ_hubspot_tasks_PK] UNIQUE ([hs_object_id])
);

